public class BreakContinue {
    public static void main(String[] args) {
        // break: find first multiple of 7 in range
        System.out.print("First multiple of 7 after 50: ");
        for (int i = 51; i <= 100; i++) {
            if (i % 7 == 0) {
                System.out.println(i);
                break;
            }
        }

        // continue: print non-multiples of 3
        System.out.print("1-15 (skip multiples of 3): ");
        for (int i = 1; i <= 15; i++) {
            if (i % 3 == 0) continue;
            System.out.print(i + " ");
        }
        System.out.println();
    }
}

public class LabeledBreak {
    public static void main(String[] args) {
        // Find the first pair (i, j) where i * j > 15
        System.out.println("Products until > 15:");

        search:
        for (int i = 1; i <= 5; i++) {
            for (int j = 1; j <= 5; j++) {
                int product = i * j;
                if (product > 15) {
                    System.out.println("\nStopped at i=" + i + ", j=" + j + " (product=" + product + ")");
                    break search; // Exits BOTH loops
                }
                System.out.print(product + "\t");
            }
            System.out.println();
        }

        System.out.println("Done.");
    }
}

public class RightTriangle {
    public static void main(String[] args) {
        int n = 5;

        // Right triangle (left-aligned)
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= i; j++) {
                System.out.print("* ");
            }
            System.out.println();
        }

        System.out.println();

        // Inverted right triangle
        for (int i = n; i >= 1; i--) {
            for (int j = 1; j <= i; j++) {
                System.out.print("* ");
            }
            System.out.println();
        }
    }
}

public class Pyramid {
    public static void main(String[] args) {
        int n = 5;

        for (int i = 1; i <= n; i++) {
            // Print leading spaces: (n - i) spaces
            for (int j = 1; j <= n - i; j++) {
                System.out.print(" ");
            }
            // Print stars: (2*i - 1) stars
            for (int j = 1; j <= 2 * i - 1; j++) {
                System.out.print("*");
            }
            System.out.println();
        }
    }
}

public class Diamond {
    public static void main(String[] args) {
        int n = 5;

        // Upper half (pyramid)
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= n - i; j++) System.out.print(" ");
            for (int j = 1; j <= 2 * i - 1; j++) System.out.print("*");
            System.out.println();
        }

        // Lower half (inverted pyramid, skip the middle row)
        for (int i = n - 1; i >= 1; i--) {
            for (int j = 1; j <= n - i; j++) System.out.print(" ");
            for (int j = 1; j <= 2 * i - 1; j++) System.out.print("*");
            System.out.println();
        }
    }
}

public class FloydTriangle {
    public static void main(String[] args) {
        int n = 5;
        int num = 1;

        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= i; j++) {
                System.out.print(num + "\t");
                num++;
            }
            System.out.println();
        }
    }
}

public class PascalTriangle {
    public static void main(String[] args) {
        int n = 6;

        for (int i = 0; i < n; i++) {
            // Leading spaces for alignment
            for (int s = 0; s < n - i - 1; s++) {
                System.out.print("  ");
            }

            int val = 1;
            for (int j = 0; j <= i; j++) {
                System.out.printf("%4d", val);
                val = val * (i - j) / (j + 1);
            }
            System.out.println();
        }
    }
}

public class CharPattern {
    public static void main(String[] args) {
        int n = 5;

        // Pattern 1: A, AB, ABC, ...
        for (int i = 0; i < n; i++) {
            for (int j = 0; j <= i; j++) {
                System.out.print((char)('A' + j) + " ");
            }
            System.out.println();
        }

        System.out.println();

        // Pattern 2: A, BB, CCC, ...
        for (int i = 0; i < n; i++) {
            for (int j = 0; j <= i; j++) {
                System.out.print((char)('A' + i) + " ");
            }
            System.out.println();
        }
    }
}

